struct DemoMapView: UIViewRepresentable {
    @Binding var coordinate: CLLocationCoordinate2D

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: coordinate.latitude, longitude: coordinate.longitude, zoom: 12)
        let mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.settings.myLocationButton = false
        mapView.settings.compassButton = true
        mapView.isMyLocationEnabled = false

        let marker = GMSMarker(position: coordinate)
        marker.title = "Demo Pin"
        marker.snippet = "Investor presentation location"
        marker.map = mapView

        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        uiView.animate(toLocation: coordinate)
    }
}

struct CheckoutView: View {
    @Binding var paymentStatus: String
    @Environment(\.dismiss) private var dismiss
    @State private var isProcessing = false
    @State private var showSuccess = false
    @State private var errorMessage: String?

    var body: some View {
        NavigationView {
            VStack(spacing: 20) {
                Text("Demo Checkout")
                    .font(.largeTitle.bold())

                Text("This is a pitch-deck-ready payment flow using Stripe PaymentSheet.")
                    .multilineTextAlignment(.center)
                    .foregroundColor(.secondary)
                    .padding(.horizontal)

                Button {
                    startPayment()
                } label: {
                    HStack {
                        if isProcessing {
                            ProgressView()
                                .tint(.white)
                        }
                        Text(isProcessing ? "Processing..." : "Complete Payment")
                            .font(.headline)
                    }
                    .frame(maxWidth: .infinity)
                    .padding()
                    .background(isProcessing ? Color.gray : Color.green)
                    .foregroundColor(.white)
                    .cornerRadius(14)
                    .padding(.horizontal)
                }
                .disabled(isProcessing)

                if let errorMessage {
                    Text(errorMessage)
                        .foregroundColor(.red)
                        .padding(.horizontal)
                }

                Spacer()
            }
            .navigationTitle("Checkout")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarLeading) {
                    Button("Close") { dismiss() }
                }
            }
            .alert("Payment Successful", isPresented: $showSuccess) {
                Button("Done") {
                    paymentStatus = "Payment completed successfully"
                    dismiss()
                }
            } message: {
                Text("Your demo payment was processed.")
            }
        }
    }

    private func startPayment() {
        isProcessing = true
        errorMessage = nil

        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
            isProcessing = false
            showSuccess = true
        }
